	(2324, 5, 'https://github.com/alirezarezvani/claude-skills/blob/main/engineering-team/skills/senior-data-scientist/references/statistical_methods_advanced.md', 'engineering-team/skills/senior-data-scientist/references/statistical_methods_advanced.md', '2ad183277b8e57a307085ca7265258d31a08761bc5d3f5844a33dbc79a40a48b', 2, 1, '2026-05-10 20:59:03.893+00', '2026-05-10 20:59:03.896237+00'),
