	(1313, 5, 'https://github.com/alirezarezvani/claude-skills/blob/main/.claude/commands/README.md', '.claude/commands/README.md', '778f4b8344090112df9d0049b34accb987a0c5b5500a7dc7594d69415492328d', 2, 1, '2026-05-11 10:36:42.793+00', '2026-05-10 20:52:28.090128+00');
INSERT INTO "public"."analysis" ("id", "file_source_id", "summary", "use_cases", "maturity", "score", "model", "created_at", "class_id") OVERRIDING SYSTEM VALUE VALUES
	(1, 1, 'This file implements a structured self-debugging workflow for AI agent failures, utilizing a four-phase loop of failure capture, root-cause diagnosis, contained recovery, and introspection reporting. It provides a systematic approach to debugging, including tools for capturing failure state, diagnosing common failure patterns, and applying recovery actions, with the goal of producing a structured human-readable debug report. The workflow includes specific templates for capturing failure information, diagnosing root causes, and reporting recovery actions, and integrates with other skills such as verification-loop, continuous-learning-v2, council, and workspace-surface-audit.', '[{"title": "Agent Failure Debugging", "description": "Use this skill to debug AI agent failures, including capturing failure state, diagnosing root causes, and applying recovery actions."}, {"title": "Workflow Integration", "description": "Integrate this skill with other workflows, such as verification-loop and continuous-learning-v2, to improve overall system reliability and performance."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:44:28.596689+00', 1),
	(2, 2, 'This file implements the agent-sort skill, which sorts ECC components into DAILY and LIBRARY buckets based on evidence from the repository, using tools like rg for file searches and commands like cat for inspecting package managers and framework configs, to produce a tailored install plan with verification report.', '[{"title": "Project-Specific ECC Installation", "description": "Use this skill to create a tailored ECC install plan for a specific project, reducing noise and improving relevance."}, {"title": "Repository Cleanup and Optimization", "description": "Apply this skill to clean up and optimize a repository by removing stale language rules, incompatible hooks, and unused surfaces."}, {"title": "Automated ECC Configuration", "description": "Leverage this skill to automate ECC configuration for a project, ensuring that only necessary components are installed and configured."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:44:34.371256+00', 1),
	(3, 3, 'This file provides a comprehensive guide to designing REST APIs, covering topics such as resource naming, HTTP methods, status codes, pagination, filtering, authentication, and rate limiting. It includes code examples in TypeScript, Python, and Go, as well as a checklist for ensuring best practices are followed when shipping new endpoints.', '[{"title": "Designing a New API Endpoint", "description": "Use this guide to ensure that your new API endpoint follows best practices for REST API design, including proper resource naming, HTTP method usage, and error handling."}, {"title": "Reviewing Existing API Endpoints", "description": "Use this guide to review existing API endpoints and identify areas for improvement, such as inconsistent naming conventions or inadequate error handling."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:44:38.864847+00', 15),
	(4, 5, 'This file provides a comprehensive guide to backend development patterns, including API design, database optimization, caching, error handling, authentication, and rate limiting. It covers various techniques such as the repository pattern, service layer pattern, and middleware pattern, and provides examples in TypeScript and JavaScript. The file also discusses the importance of logging, monitoring, and testing in ensuring the reliability and scalability of backend applications.', '[{"title": "Building a Scalable API", "description": "Use the repository pattern and service layer pattern to build a scalable API that can handle a large number of requests."}, {"title": "Optimizing Database Performance", "description": "Use caching and database optimization techniques to improve the performance of your database and reduce latency."}, {"title": "Implementing Authentication and Authorization", "description": "Use JWT tokens and role-based access control to implement authentication and authorization in your backend application."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:44:45.116159+00', 15),
	(5, 6, 'This file describes a skill for building a source-derived writing style profile from real posts, essays, launch notes, docs, or site copy, then reusing that profile across content, outreach, and social workflows, specifically using tools like x-api to pull recent original posts and following a collection workflow to gather representative samples, extract rhythm, sentence length, and other stylistic elements, and produce a reusable VOICE PROFILE block that downstream skills can consume directly.', '[{"title": "Consistent Brand Voice", "description": "Use this skill to create a consistent brand voice across all content, outreach, and social media channels, ensuring that the tone and style of the writing is consistent and engaging."}, {"title": "Content Engine Optimization", "description": "Use this skill to optimize the content engine by providing a reusable voice profile that can be used to generate high-quality content that resonates with the target audience."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 17:44:49.669219+00', 1),
	(17, 18, 'Exa Search provides neural search capabilities via the Exa MCP server for web content, code, companies, and people, utilizing tools such as web_search_exa, web_search_advanced_exa, get_code_context_exa, company_research_exa, people_search_exa, crawling_exa, deep_researcher_start, and deep_researcher_check, allowing for comprehensive research and information gathering with features like filtered search, code examples, and company intelligence.', '[{"title": "Quick Lookup", "description": "Using web_search_exa for broad queries to find current information or news."}, {"title": "Code Research", "description": "Utilizing get_code_context_exa to find code examples and documentation for specific programming topics."}, {"title": "Company Due Diligence", "description": "Combining company_research_exa with web_search_advanced_exa for thorough company analysis and business intelligence."}, {"title": "Technical Deep Dive", "description": "Starting async research with deep_researcher_start for comprehensive topics that benefit from AI synthesis and checking status with deep_researcher_check."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:24.575492+00', 1),
	(48, 27, 'This file provides guidance on using Turbopack with Next.js 16+ for incremental bundling, file-system caching, and faster development speed, including when to use Turbopack versus webpack, and how to optimize production bundles and diagnose slow dev startup or hot module replacement issues.', '[{"title": "Faster Development", "description": "Use Turbopack for day-to-day development to speed up dev startup and hot updates, especially in large Next.js applications."}, {"title": "Production Bundle Optimization", "description": "Use the official Next.js bundle analysis tooling to optimize production bundle sizes and diagnose issues."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:40:45.309123+00', 15),
	(6, 7, 'This file provides a voice profile schema, outlining the structure for building a reusable voice profile, including sections such as source set, rhythm, compression, capitalization, parentheticals, question use, claim style, preferred moves, banned moves, CTA rules, and channel notes, with guidelines for keeping the profile concrete, using short bullets, and handling conflicts in the source set.', '[{"title": "Content Creation", "description": "Use this voice profile schema to create consistent content across different channels and platforms."}, {"title": "Brand Identity", "description": "Apply this voice profile schema to establish a unique and recognizable brand voice."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 17:44:52.048477+00', 15),
	(7, 8, 'The Bun runtime is a fast all-in-one JavaScript runtime and toolkit that serves as a runtime, package manager, bundler, and test runner, offering a drop-in Node-compatible runtime, a significantly faster package manager than npm/yarn, a built-in bundler and transpiler, and a built-in test runner with a Jest-like API, making it suitable for new JS/TS projects, scripts where install/run speed matters, Vercel deployments, and single toolchain needs.', '[{"title": "New Project Setup", "description": "Use Bun as the runtime, package manager, bundler, and test runner for new JavaScript or TypeScript projects, taking advantage of its speed and single toolchain."}, {"title": "Migration from Node", "description": "Migrate existing Node projects to Bun, replacing Node commands with Bun equivalents, such as using `bun run` instead of `node`, and `bun install` instead of `npm install`."}, {"title": "Vercel Deployment", "description": "Use Bun as the runtime on Vercel, setting the runtime to Bun in project settings, and using `bun run build` or `bun build` to build the project, and `bun install --frozen-lockfile` for reproducible deploys."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:44:54.792254+00', NULL),
	(8, 9, 'This file provides a comprehensive guide to coding standards, covering best practices for naming conventions, code quality, error handling, and performance optimization. It includes examples in TypeScript and JavaScript, as well as guidelines for React, API design, and testing. The file emphasizes the importance of clear, maintainable code and provides tips for avoiding common anti-patterns and code smells.', '[{"title": "New Project Setup", "description": "Use this guide to establish coding standards for a new project, ensuring consistency and maintainability from the start."}, {"title": "Code Review", "description": "Apply these guidelines during code reviews to ensure that code meets the highest standards of quality, readability, and performance."}, {"title": "Legacy Code Refactoring", "description": "Use this guide to refactor legacy code, improving its quality, readability, and maintainability, and reducing technical debt."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:44:58.209617+00', 15),
	(10, 11, 'The crosspost skill distributes content across multiple social platforms, including X, LinkedIn, Threads, and Bluesky, adapting the content per platform using content-engine patterns and preserving the author''s voice while avoiding identical posts, it utilizes tools like content-engine and brand-voice to capture the voice fingerprint and shape the content, and follows specific rules for each platform, such as keeping it compressed on X and avoiding hashtags and generic filler', '[{"title": "Multi-Platform Content Distribution", "description": "Use the crosspost skill to distribute content across multiple social platforms, adapting the content per platform to maximize engagement and reach a wider audience"}, {"title": "Content Adaptation for Different Audiences", "description": "Utilize the crosspost skill to adapt content for different audiences on various social platforms, ensuring that the content is tailored to each platform''s unique constraints and audience"}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:45:05.766315+00', 1),
	(11, 12, 'This file implements a deep research skill that utilizes firecrawl and exa MCP tools to conduct thorough, multi-source research on any given topic, synthesizing findings into a cited report with source attribution, covering various domains such as technology evaluation, market sizing, and due diligence, and following a structured workflow that includes understanding the goal, planning the research, executing multi-source searches, deep-reading key sources, synthesizing and writing the report, and delivering the findings.', '[{"title": "Competitive Analysis", "description": "Use this skill to research competitors, including their products, services, and market strategies, and gain insights into their strengths and weaknesses."}, {"title": "Technology Evaluation", "description": "Utilize this skill to evaluate new technologies, including their potential applications, benefits, and drawbacks, and make informed decisions about adoption and implementation."}, {"title": "Market Sizing", "description": "Employ this skill to estimate the size of a market, including the number of potential customers, revenue potential, and growth prospects, and develop effective marketing strategies."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:02.292287+00', 1),
	(13, 14, 'This file implements a documentation lookup skill that utilizes the Context7 MCP server to fetch current documentation for libraries and frameworks, providing up-to-date information for setup questions, API references, and code examples. It leverages tools like resolve-library-id and query-docs to resolve library IDs and query documentation, ensuring accurate and relevant results for user queries.', '[{"title": "Setup and Configuration", "description": "The skill helps users set up and configure libraries and frameworks by providing accurate and up-to-date documentation."}, {"title": "Code Examples and Snippets", "description": "The skill fetches relevant code examples and snippets from the documentation to help users with their coding tasks."}, {"title": "API References and Information", "description": "The skill provides users with accurate and up-to-date information about APIs, including references and documentation."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:10.077353+00', 1),
	(14, 15, 'This file provides comprehensive Playwright patterns for building stable, fast, and maintainable E2E test suites, including test file organization, Page Object Model, configuration, CI/CD integration, artifact management, and flaky test strategies, utilizing tools like Playwright, TypeScript, and GitHub Actions.', '[{"title": "E2E Testing for Web Applications", "description": "Use this framework to write end-to-end tests for web applications, ensuring that the application works as expected from a user''s perspective."}, {"title": "Automated Testing for Critical Flows", "description": "Utilize this framework to automate tests for critical flows, such as financial transactions or user authentication, to ensure that these flows work correctly and securely."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:13.531068+00', 12),
	(15, 16, 'This file implements a formal evaluation framework for Claude Code sessions, providing a structured approach to defining and running capability and regression evals, tracking pass@k metrics, and ensuring reliability in AI-assisted workflows. It includes tools like code-based graders, model-based graders, and human graders to assess code changes, and provides integration patterns for pre-implementation, during implementation, and post-implementation phases.', '[{"title": "AI-Assisted Workflow Evaluation", "description": "Use this framework to evaluate the reliability and performance of AI-assisted workflows, ensuring that they meet the required standards and pass@k metrics."}, {"title": "Code Change Evaluation", "description": "Apply this framework to assess the impact of code changes on the overall system, using capability and regression evals to catch regressions and ensure reliability."}, {"title": "Model-Based Grading", "description": "Utilize model-based graders to evaluate open-ended outputs, such as code changes or user input, and provide a score based on the evaluation criteria."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:17.490155+00', 13),
	(16, 17, 'This file describes the development conventions and patterns for the everything-claude-code JavaScript project, including commit message guidelines, architecture, code style, testing, error handling, and common workflows such as database migration, feature development, and adding new skills or agents.', '[{"title": "Onboarding New Developers", "description": "Use this guide to introduce new developers to the project''s conventions, architecture, and best practices."}, {"title": "Maintaining Code Quality", "description": "Follow the guidelines in this file to ensure consistent code quality, formatting, and testing across the project."}, {"title": "Adding New Features", "description": "Refer to this guide when adding new features to the project, to ensure that they align with the established patterns and conventions."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 17:46:21.298162+00', 15),
	(18, 19, 'The fal-ai-media skill utilizes the fal.ai MCP server to generate images, videos, and audio using various models such as Nano Banana, Seedance, Kling, Veo 3, and CSM-1B, allowing for text-to-image, text-to-video, image-to-video, and text-to-speech capabilities, with features like cost estimation, model discovery, and reproducible results using seeds.', '[{"title": "Automated Content Creation", "description": "Use the fal-ai-media skill to generate images, videos, and audio for social media, advertising, and other content creation tasks, streamlining the process and reducing production time."}, {"title": "AI-Powered Video Editing", "description": "Leverage the skill''s video generation and editing capabilities to create engaging videos with minimal manual effort, ideal for vloggers, YouTubers, and social media influencers."}, {"title": "Personalized Audio Content", "description": "Utilize the skill''s text-to-speech and audio generation features to create customized audio content, such as podcasts, audiobooks, or voice assistants, tailored to individual preferences and needs."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:28.0752+00', 1),
	(25, 4, 'This article-writing skill generates polished long-form content, such as blog posts, guides, and tutorials, in a distinctive voice derived from supplied examples or brand guidance, using concrete examples, tight sentences, and proof instead of adjectives, while avoiding generic AI patterns and banned phrases like ''game-changer'' or ''cutting-edge'', and following a structured writing process with a focus on clarity, purpose, and audience, including specific guidance for technical guides, essays, and newsletters, and a quality gate to ensure factual accuracy, voice consistency, and formatting suitability', '[{"title": "Blog Post Writing", "description": "Use this skill to generate high-quality blog posts that engage and inform readers, with a focus on clarity, structure, and credibility"}, {"title": "Technical Guide Creation", "description": "Leverage this skill to produce comprehensive technical guides that provide actionable takeaways and concrete examples, using code, commands, and screenshots to illustrate key points"}, {"title": "Newsletter Content Generation", "description": "Utilize this skill to generate compelling newsletter content that resonates with readers, with a focus on scannability, structure, and relevance"}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:36:48.078396+00', 1),
	(19, 20, 'This file provides a comprehensive collection of modern frontend development patterns for React, Next.js, and performant user interfaces, including component composition, custom hooks, state management, performance optimization, form handling, error boundaries, animations, and accessibility patterns.', '[{"title": "Building a Complex User Interface", "description": "Use this guide to learn how to build complex user interfaces with React, Next.js, and modern frontend development patterns."}, {"title": "Optimizing Frontend Performance", "description": "Apply the performance optimization patterns from this guide to improve the speed and efficiency of your frontend application."}, {"title": "Ensuring Accessibility in Frontend Development", "description": "Follow the accessibility patterns outlined in this guide to ensure that your frontend application is accessible to all users."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:31.964366+00', 15),
	(21, 23, 'The investor-materials file provides a framework for creating and updating pitch decks, one-pagers, investor memos, accelerator applications, financial models, and fundraising materials. It guides the user through a core workflow of inventorying canonical facts, identifying missing assumptions, choosing the asset type, drafting the asset with explicit logic, and cross-checking every number against the source of truth. Notable behaviors include the use of a single source of truth, explicit assumptions, and sensitivity analysis, as well as the avoidance of red flags such as unverifiable claims, fuzzy market sizing, and inflated certainty.', '[{"title": "Creating a Pitch Deck", "description": "Use this guide to create a pitch deck that is consistent, credible, and easy to defend, including a recommended flow and tips for drafting and reviewing the deck."}, {"title": "Writing an Investor Memo", "description": "Use this guide to write an investor memo that is clear, concise, and effective, including tips for stating what the company does, showing why now, and making the ask precise."}, {"title": "Building a Financial Model", "description": "Use this guide to build a financial model that is explicit, layered, and milestone-linked, including tips for including assumptions, bear/base/bull cases, and sensitivity analysis."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 17:48:05.216109+00', 15),
	(9, 10, 'The content-engine file provides a framework for creating platform-native content systems across various social media platforms, including X, LinkedIn, TikTok, YouTube, and newsletters. It outlines a source-first workflow, voice handling, and platform adaptation rules to ensure high-quality content that maintains the author''s real voice. The file includes specific guidelines for each platform, such as opening with the strongest claim on X, expanding context on LinkedIn, and scripting around visual sequences on short-form video. It also defines a repurposing flow to adapt content across multiple platforms, ensuring that each output contains a real claim, proof point, or concrete observation.', '[{"title": "Social Media Campaigns", "description": "Use the content-engine skill to create platform-native content for social media campaigns, ensuring that each post sounds like the intended author and contains a real claim or proof point."}, {"title": "Content Repurposing", "description": "Utilize the content-engine skill to repurpose existing content across multiple platforms, adapting the structure and tone to fit each platform''s unique requirements."}, {"title": "Voice Profile Creation", "description": "Leverage the content-engine skill to create source-derived voice profiles, ensuring that the tone and style of the content align with the intended author''s voice."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:45:01.467687+00', 1),
	(12, 13, 'The dmux-workflows file enables multi-agent orchestration using dmux, a tmux pane manager for AI agents, allowing for parallel agent workflows across various harnesses like Claude Code, Codex, and OpenCode, with features like creating new panes, merging output, and supporting multiple tools, and providing patterns for research, implementation, multi-file features, test and fix loops, cross-harness workflows, and code review pipelines.', '[{"title": "Multi-Agent Development Workflows", "description": "Use dmux to coordinate multiple AI agent sessions in parallel, streamlining development workflows and improving productivity."}, {"title": "Parallel Testing and Debugging", "description": "Utilize dmux to run tests in parallel, identify issues, and debug code efficiently, reducing overall development time."}, {"title": "Cross-Harness Workflows", "description": "Leverage dmux to integrate multiple AI tools and harnesses, enabling seamless workflows across different platforms and frameworks."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:46:06.843199+00', 1),
	(42, 21, 'This file generates zero-dependency, animation-rich HTML presentations from scratch or by converting PowerPoint files, using a visual exploration approach to help non-designers discover their aesthetic, with features such as viewport fit, production quality code, and distinctive design, while avoiding generic templates and ensuring accessibility and responsiveness.', '[{"title": "Creating a Talk Deck", "description": "Use this skill to create a stunning presentation for a conference talk, workshop, or pitch, with a focus on visual exploration and distinctive design."}, {"title": "Converting PowerPoint Files", "description": "Convert existing PowerPoint files to HTML presentations, preserving slide order, speaker notes, and extracted assets, while ensuring accessibility and responsiveness."}, {"title": "Improving Existing Presentations", "description": "Enhance existing HTML presentations by improving layout, motion, and typography, while ensuring production quality code and respecting reduced motion preferences."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:39:55.512575+00', 1),
	(20, 22, 'This file provides a comprehensive guide to creating visually appealing and responsive slides for presentations, including a mandatory viewport-fitting CSS base, preset selection and mood mapping, CSS gotchas, and validation rules. It covers various aspects such as typography, spacing, images, grids, and breakpoints, and includes a catalog of 12 presets with distinct vibes, fonts, palettes, and signatures. The file also provides guidelines for animation feel mapping, direct selection prompts, and anti-patterns to avoid.', '[{"title": "Creating a Presentation", "description": "Use this file to create a visually appealing and responsive presentation with a consistent design language."}, {"title": "Customizing a Theme", "description": "Use the preset catalog and mood mapping guidelines to customize a theme for a presentation or website."}, {"title": "Optimizing for Different Devices", "description": "Use the validation sizes and breakpoints guidelines to ensure that the presentation or website looks good on different devices and screen sizes."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 17:48:02.539816+00', 8),
	(45, 24, 'The investor-outreach skill drafts cold emails, warm intro blurbs, follow-ups, update emails, and investor communications for fundraising, providing concise, personalized, investor-facing messaging. It uses a structured approach with a focus on personalization, low-friction asks, and concrete proof points, and includes features such as voice handling, hard bans on certain phrases, and a quality gate to ensure high-quality output.', '[{"title": "Fundraising Campaign", "description": "Use the investor-outreach skill to draft personalized emails and messages to potential investors, increasing the chances of a successful fundraising campaign."}, {"title": "Investor Relations", "description": "Utilize the investor-outreach skill to maintain relationships with existing investors, providing them with regular updates and personalized communication."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:40:29.877238+00', 1),
	(46, 25, 'This file outlines a market research skill that supports business decisions through source-attributed and decision-oriented summaries, covering market sizing, competitor comparisons, fund research, and technology scans, with a focus on providing actionable insights and recommendations.', '[{"title": "Market Sizing", "description": "Estimate the size of a market or category to inform business decisions"}, {"title": "Competitor Comparison", "description": "Compare competitors or adjacent products to identify strengths, weaknesses, and positioning gaps"}, {"title": "Investor Due Diligence", "description": "Conduct research on investors or funds to inform outreach or investment decisions"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:40:31.017401+00', 1),
	(47, 26, 'This MCP server pattern provides a comprehensive guide on building MCP servers using the Node/TypeScript SDK, including tools, resources, prompts, Zod validation, and stdio vs Streamable HTTP. It covers core concepts such as tools, resources, prompts, and transport, and provides examples and best practices for implementing and maintaining MCP servers.', '[{"title": "Building an MCP Server", "description": "Use this pattern to build a new MCP server from scratch, including setting up tools, resources, and prompts."}, {"title": "Upgrading an Existing MCP Server", "description": "Use this pattern to upgrade an existing MCP server to the latest SDK version, including updating tools, resources, and prompts."}, {"title": "Debugging MCP Registration and Transport Issues", "description": "Use this pattern to debug issues with MCP registration and transport, including troubleshooting stdio and Streamable HTTP connections."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:40:38.860135+00', 5),
	(49, 28, 'This file describes a skill that translates product intent into an implementation-ready capability plan, exposing constraints, invariants, interfaces, and unresolved decisions before multi-service work starts, using tools like PRD, roadmap items, and product discussions to create a durable product-context file, and following a core workflow that involves restating the capability, resolving capability constraints, defining the implementation-facing contract, and translating into execution.', '[{"title": "Product Planning", "description": "Use this skill to turn product intent into explicit engineering constraints, creating a reusable artifact that can survive across harnesses and sessions."}, {"title": "Multi-Service Implementation", "description": "Apply this skill when a feature crosses multiple services, repos, or teams, and needs a capability contract before coding."}, {"title": "Architecture and Data Implications", "description": "Utilize this skill to clarify architecture, data, lifecycle, or policy implications that are still fuzzy, and to create a durable product-context file."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:40:53.380214+00', 1),
	(51, 30, 'This strategic compact skill suggests manual context compaction at logical intervals to preserve context through task phases, rather than relying on arbitrary auto-compaction, by tracking tool calls and suggesting compaction at configurable thresholds, with features like periodic reminders and customizable environment variables.', '[{"title": "Optimizing Context for Long Sessions", "description": "Use the strategic compact skill to preserve context and improve performance during long sessions or multi-phase tasks."}, {"title": "Improving Response Coherence", "description": "Activate the strategic compact skill to reduce context pressure and improve response coherence when working on complex tasks."}, {"title": "Streamlining Task Transitions", "description": "Use the strategic compact skill to clear context and start fresh when switching between unrelated tasks or phases."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:41:20.54679+00', 1),
	(50, 29, 'This security review skill provides a comprehensive checklist and patterns to ensure all code follows security best practices and identifies potential vulnerabilities, covering areas such as secrets management, input validation, SQL injection prevention, authentication and authorization, XSS prevention, CSRF protection, rate limiting, sensitive data exposure, blockchain security, and dependency security.', '[{"title": "Web Application Security", "description": "Use this skill to review and secure web applications, ensuring they follow best practices and are protected against common vulnerabilities."}, {"title": "API Security", "description": "Apply this skill to secure APIs, protecting against unauthorized access, data breaches, and other security threats."}, {"title": "Blockchain Security", "description": "Utilize this skill to review and secure blockchain-based applications, ensuring the security and integrity of transactions and data."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:41:12.448471+00', 1),
	(52, 31, 'This file implements a comprehensive test-driven development workflow, enforcing 80%+ test coverage for unit, integration, and E2E tests, with a focus on writing tests first, using Jest and Playwright for testing, and following best practices such as one assert per test, descriptive test names, and mocking external dependencies.', '[{"title": "New Feature Development", "description": "Use this workflow when developing new features to ensure comprehensive test coverage and high-quality code."}, {"title": "Bug Fixing", "description": "Apply this workflow when fixing bugs to guarantee that the fixes are thoroughly tested and do not introduce new issues."}, {"title": "Code Refactoring", "description": "Follow this workflow during code refactoring to maintain high test coverage and ensure the refactored code is reliable and stable."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:41:36.123816+00', 1),
	(53, 32, 'The verification-loop skill provides a comprehensive verification system for Claude Code sessions, including build verification, type checking, lint checking, test suite execution, security scanning, and diff review, with a final verification report indicating readiness for a PR.', '[{"title": "Pre-PR Verification", "description": "Use the verification-loop skill to ensure code quality and readiness before creating a PR."}, {"title": "Continuous Verification", "description": "Run the verification-loop skill every 15 minutes or after major changes during long coding sessions to maintain code quality and catch issues early."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:41:43.089336+00', 1),
	(54, 33, 'This file outlines a comprehensive AI-assisted video editing workflow, covering the full pipeline from raw capture through various tools like FFmpeg, Remotion, ElevenLabs, fal.ai, and final polish in Descript or CapCut, with a focus on editing existing video footage rather than generating new content from prompts.', '[{"title": "AI-assisted Video Editing", "description": "Use this workflow to edit and refine existing video footage, leveraging AI tools for tasks like organization, deterministic cuts, and generated assets."}, {"title": "Automated Video Content Creation", "description": "Apply this workflow to streamline the creation of video content, such as vlogs, tutorials, or demo videos, by automating repetitive tasks and focusing on creative decisions."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:41:59.044033+00', 11),
	(55, 34, 'This file provides an integration with the X/Twitter API for posting tweets, threads, reading timelines, search, and analytics, covering OAuth authentication patterns, rate limits, and platform-native content posting. It includes concrete examples of how to post a tweet, post a thread, read a user timeline, search tweets, and upload media and post, all using the X API. The file also covers error handling, security considerations, and integration with a content engine for generating platform-native content.', '[{"title": "Posting Tweets Programmatically", "description": "Use the X API to post tweets programmatically, including posting threads and uploading media."}, {"title": "Reading User Timelines", "description": "Use the X API to read user timelines, including reading recent tweets and searching for specific content."}, {"title": "Analytics and Engagement Tracking", "description": "Use the X API to track engagement and analytics for tweets and threads, including tracking likes, retweets, and replies."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:42:10.933538+00', 6),
	(56, 35, 'The plugin.json file enforces strict constraints such as requiring component fields to be arrays, excluding the ''agents'' field, and mandating a ''version'' field for reliable validation and installation. Custom endpoints and gateways are supported through Claude Code''s environment and configuration settings, allowing for the use of official LLM gateways or compatible custom endpoints.', '[{"title": "Custom Gateway Setup", "description": "Configure Claude Code to use a custom endpoint or gateway for LLM interactions"}, {"title": "Plugin Development", "description": "Create and validate plugins for Claude Code, adhering to the strict constraints and guidelines"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:15.9126+00', 6),
	(57, 36, 'This workflow command scaffold, add-language-rules, enables the addition of new programming languages to the rules system in everything-claude-code, incorporating tools like Bash, Read, Write, Grep, and Glob to manage coding style, hooks, patterns, security, and testing guidelines.', '[{"title": "Adding a new language", "description": "Use this workflow to add a new programming language to the rules system, including coding style, hooks, patterns, security, and testing guidelines"}, {"title": "Updating existing language rules", "description": "Modify the existing language rules by following the suggested sequence and typical commit signals to ensure a smooth update process"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:20.752663+00', 11),
	(58, 37, 'This file provides a workflow command scaffold for database-migration in everything-claude-code, utilizing tools like Bash, Read, Write, Grep, and Glob to manage schema changes and migration files, with suggested sequences and typical commit signals for tasks such as creating migration files, updating schema definitions, and generating types.', '[{"title": "Database Schema Updates", "description": "Use this workflow to manage database schema changes and migration files in a controlled and systematic way"}, {"title": "Migration File Creation", "description": "Utilize the suggested sequence and typical commit signals to create and manage migration files effectively"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:25.03547+00', 11),
	(59, 38, 'This workflow command scaffold is designed for feature development in everything-claude-code, utilizing tools like Bash, Read, Write, Grep, and Glob to manage files such as manifests, schemas, and API files, and suggests a sequence of understanding the current state, making coherent changes, running verification, and summarizing changes.', '[{"title": "New Feature Implementation", "description": "Use this workflow when implementing a new feature in everything-claude-code to ensure a standardized approach."}, {"title": "Existing Feature Update", "description": "Apply this workflow when updating an existing feature to maintain consistency and verify changes."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:29.300406+00', 11),
	(60, 39, 'This file serves as a starter governance file for enterprise ECC deployments, providing guidelines for repository management, profile recommendations, and approval expectations, including security-sensitive workflow changes, audit suppressions, and generated skills review.', '[{"title": "Enterprise Deployment", "description": "Use this governance file as a starting point for ECC deployments in an enterprise setting"}, {"title": "Security Review", "description": "Apply the approval expectations outlined in this file to ensure security-sensitive workflow changes are properly reviewed"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:43.207257+00', 15),
	(64, 43, 'This file outlines development conventions and patterns for the everything-claude-code project, including commit message guidelines, architecture, code style, testing, error handling, and common workflows such as database migration, feature development, and adding new skills or agents. It provides specific examples of commit messages, code snippets, and file patterns to follow, ensuring consistency and quality across the project.', '[{"title": "Onboarding New Developers", "description": "Use this guide to introduce new developers to the project''s coding standards, best practices, and workflows, ensuring a smooth onboarding process."}, {"title": "Maintaining Code Quality", "description": "Refer to this guide to maintain high code quality, adhere to established patterns, and ensure consistency across the project, making it easier to collaborate and maintain the codebase."}, {"title": "Improving Development Efficiency", "description": "Follow the guidelines and best practices outlined in this document to streamline development workflows, reduce errors, and improve overall efficiency, leading to faster time-to-market and increased productivity."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:43:05.491216+00', 15),
	(65, 44, 'This file integrates Everything Claude Code (ECC) workflows into the CodeBuddy IDE, providing custom commands, agents, skills, and rules that can be installed using the unified Target Adapter architecture, with features like install-state tracking, doctor checks, repair, and selective install.', '[{"title": "Streamlined Development Workflow", "description": "Use ECC workflows in CodeBuddy to plan, write, review, and test code efficiently."}, {"title": "AI-Powered Code Assistance", "description": "Leverage ECC''s AI capabilities to automate tasks, such as code review and build fixes, within the CodeBuddy IDE."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:43:12.973679+00', 1),
	(70, 49, 'The content-engine file provides a comprehensive framework for creating platform-native content systems across various social media platforms, including X, LinkedIn, TikTok, YouTube, and newsletters, with guidelines on adapting content, using hooks, and keeping asks small and clear, as well as specific rules for each platform, such as opening fast on X, using strong first lines on LinkedIn, and scripting around visuals on TikTok and short video.', '[{"title": "Social Media Campaigns", "description": "Use the content-engine to create platform-native content for social media campaigns, including X posts, LinkedIn updates, TikTok videos, and YouTube explainers."}, {"title": "Content Repurposing", "description": "Utilize the content-engine to repurpose articles, podcasts, demos, or docs into social content, such as adapting a blog post into a series of X posts or a LinkedIn update."}, {"title": "Launch Support", "description": "Leverage the content-engine to build a lightweight content plan around a launch, milestone, or theme, including platform-specific drafts and optional posting orders."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:43:48.158037+00', 15),
	(72, 103, 'This file provides guidance on creating and updating investor-facing materials such as pitch decks, one-pagers, investor memos, accelerator applications, financial models, and fundraising materials, ensuring consistency and credibility across multiple documents. It outlines a core workflow, asset-specific guidance, and red flags to avoid, focusing on explicit logic, verifiable claims, and internal consistency.', '[{"title": "Creating a Pitch Deck", "description": "Use this guide to create a pitch deck that is consistent, credible, and easy to defend, including a recommended flow and tips for drafting."}, {"title": "Writing an Investor Memo", "description": "Follow this guide to write a clear and concise investor memo, including a one-sentence company description, traction and proof points, and a precise ask."}, {"title": "Building a Financial Model", "description": "Use this guide to build a financial model that includes explicit assumptions, bear/base/bull cases, clean revenue logic, and milestone-linked spending."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:44:04.391433+00', 15),
	(61, 40, 'This file outlines a research playbook for tasks that require extensive documentation, source sensitivity, or broad repository context, emphasizing the use of primary documentation, direct source links, and concrete dates, with a suggested flow of inspecting local code and docs, browsing for unstable or external facts, and summarizing findings with file paths, commands, or links, while also detecting repository signals such as primary language and workflows.', '[{"title": "Documentation-Heavy Tasks", "description": "Use this playbook when working on tasks that require extensive documentation and source sensitivity"}, {"title": "Repository Context", "description": "Apply this playbook when tasks require broad repository context and understanding of workflows"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:44.645064+00', 15),
	(62, 41, 'This file outlines the code guardrails for a repository, including commit workflow, architecture, code style, and ECC defaults. It specifies the use of conventional commit messaging, a hybrid module organization, camelCase file naming, and relative imports. It also detects workflows such as database migration, feature development, and adding language rules, and provides reminders for regenerating the bundle and keeping suppressions narrow and auditable.', '[{"title": "Repository Setup", "description": "Use this guide to set up a new repository with the correct code guardrails and workflows"}, {"title": "Code Review", "description": "Use this guide to review code changes and ensure they align with the repository''s conventions and standards"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:42:45.845054+00', 15),
	(67, 46, 'This file provides a Codex plugin manifest for Everything Claude Code, including 182 skills for tasks like TDD, security, and code review, as well as 6 MCP servers for GitHub API access, live documentation lookup, neural web search, persistent memory, browser automation, and step-by-step reasoning. The plugin can be installed via the Codex CLI and registers under the short slug ''ecc''.', '[{"title": "Automated Code Review", "description": "Use the plugin''s skills to automate code review tasks, such as checking for security vulnerabilities and enforcing coding standards."}, {"title": "AI-Powered Web Search", "description": "Leverage the neural web search MCP server to find relevant information and answers to programming questions."}, {"title": "End-to-End Testing", "description": "Utilize the playwright MCP server to automate browser interactions and test web applications."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:43:26.908503+00', 6),
	(69, 48, 'The Bun runtime provides a fast all-in-one JavaScript toolkit, serving as a runtime, package manager, bundler, and test runner, with features like a drop-in Node-compatible runtime, significantly faster package installation, and built-in bundler and transpiler, making it suitable for new JS/TS projects, scripts where install/run speed matters, and Vercel deployments.', '[{"title": "New Project Setup", "description": "Use Bun as the runtime, package manager, and bundler for new JavaScript or TypeScript projects, taking advantage of its speed and single toolchain."}, {"title": "Migration from Node", "description": "Migrate existing Node projects to Bun, replacing Node commands with Bun equivalents, such as using `bun run` instead of `node`, and `bun install` instead of `npm install`."}, {"title": "Vercel Deployment", "description": "Deploy Bun projects to Vercel, setting the runtime to Bun in project settings, and using Bun''s built-in bundler and test runner for efficient deployment and testing."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-10 20:43:41.468824+00', NULL),
	(63, 42, 'This file outlines the rules and conventions for the everything-claude-code project, including Node.js runtime requirements, testing procedures, code style guidelines, and hook development best practices. It specifies the use of CommonJS, ESLint, and markdownlint-cli, and provides details on file naming, structure, and content. The file also covers hook development, including async hooks, blocking hooks, and the use of the run-with-flags.js wrapper.', '[{"title": "Project Setup", "description": "Use this guide to set up a new project with the everything-claude-code codebase, including configuring the Node.js runtime, test runner, and linter."}, {"title": "Hook Development", "description": "Follow the guidelines in this file to develop custom hooks for the everything-claude-code project, including async hooks, blocking hooks, and using the run-with-flags.js wrapper."}, {"title": "Code Style and Conventions", "description": "Refer to this guide to ensure that your code adheres to the project''s code style and conventions, including file naming, structure, and content."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:42:52.428511+00', 15),
	(66, 45, 'The Everything Claude Code (ECC) for CodeBuddy repository provides a set of commands, agents, skills, and rules that can be installed into any CodeBuddy project using a unified Target Adapter architecture, offering features such as installation state tracking, doctor checks, repair, and selective installation, with commands like `/plan`, `/tdd`, `/code-review`, and `/build-fix` for tasks like planning, test-driven development, code review, and build error fixing.', '[{"title": "Streamlined Development Workflow", "description": "Use ECC for CodeBuddy to streamline development workflow with features like automated code review, test-driven development, and build error fixing."}, {"title": "Improved Code Quality", "description": "Leverage ECC''s code review and testing capabilities to ensure high-quality code and reduce errors."}, {"title": "Enhanced Productivity", "description": "Boost productivity with ECC''s planning and project management features, allowing developers to focus on writing code."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:43:20.901554+00', 1),
	(68, 47, 'This file contains guidelines for writing high-quality, long-form content such as articles, guides, blog posts, and tutorials in a distinctive voice derived from supplied examples or brand guidance, with a focus on voice consistency, structure, and credibility, using tools like voice capture workflow and quality gate checks to ensure polished written content that sounds like a real person or brand.', '[{"title": "Content Creation", "description": "Use this guide to create high-quality, engaging content for various platforms, including blog posts, articles, and tutorials."}, {"title": "Brand Voice Consistency", "description": "Apply the voice capture workflow to maintain a consistent brand voice across all content, ensuring credibility and recognition."}, {"title": "Technical Writing", "description": "Follow the structure guidance for technical guides, essays, and opinion pieces to produce well-structured and informative content."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:43:34.06383+00', 15),
	(71, 50, 'This file implements a skill for fetching current documentation via the Context7 MCP server, using tools like resolve-library-id and query-docs to provide up-to-date information on libraries, frameworks, and APIs, such as React, Next.js, and Prisma, and handles setup questions, API references, and code examples, while ensuring version awareness and preferring official sources.', '[{"title": "Setup and Configuration", "description": "Use this skill to answer setup and configuration questions for various libraries and frameworks, such as Next.js middleware or Prisma queries."}, {"title": "API References and Code Examples", "description": "Utilize this skill to provide accurate and up-to-date API references and code examples for different libraries and frameworks, like React or Supabase."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-10 20:43:57.834359+00', 1),
	(73, 992, 'This file contains legacy command shims for compatibility with old muscle-memory commands such as /tdd, /eval, or /verify, which are no longer loaded by the default plugin command surface and should be replaced with canonical skills or maintained commands.', '[{"title": "Temporary Migration Compatibility", "description": "Use these shims to maintain compatibility with old muscle-memory commands during a temporary migration period."}, {"title": "Local Command Customization", "description": "Copy individual Markdown files into a project-level or user-level directory to customize commands locally without enabling the full archive by default."}]', 'abandoned', 4, 'llama-3.3-70b-versatile', '2026-05-10 20:50:19.579711+00', 3),
	(74, 1313, 'This file contains a set of Git workflow and quality assurance commands for the claude-skills repository, including /git:cm for staging and committing, /git:cp for staging, committing, and pushing, /git:pr for creating pull requests, /review for running local quality checks, and /security-scan for running security validation. It also outlines a standard feature development workflow, provides a quick reference for commands, and details commit message formats.', '[{"title": "Quick Fix", "description": "Use /review for a quick check, then /git:cp to commit and push changes"}, {"title": "New Skill Addition", "description": "Create a new skill directory and files, validate with /review, check for security issues with /security-scan, commit locally with /git:cm, test the skill, then push and create a PR with /git:cp and /git:pr"}, {"title": "Major Feature with Multiple Skills", "description": "Work on a branch, add multiple skills, commit each skill with /git:cm, run final quality checks with /review and /security-scan, then push and create a PR"}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:36:44.042301+00', 1),
	(75, 1314, 'The focused-fix skill systematically repairs a feature or module by executing a 5-phase protocol: SCOPE, TRACE, DIAGNOSE, FIX, and VERIFY. It uses commands like /focused-fix and reads from engineering/focused-fix/SKILL.md to guide the repair process, ensuring a thorough and structured approach to fixing code issues.', '[{"title": "Feature Repair", "description": "Use the focused-fix skill to systematically repair a broken feature in a large codebase"}, {"title": "Code Refactoring", "description": "Apply the 5-phase protocol to refactor a complex module and improve its maintainability"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:45.387495+00', 1),
	(76, 1315, 'This script cleans up merged branches locally and on remote, keeping only main, dev, and gh-pages. It lists local branches to delete, deletes local branches that are fully merged, lists remote branches to delete, confirms with the user before deleting remote branches, prunes stale remote refs, and reports the final state.', '[{"title": "Cleaning up a repository after a merge", "description": "Use this script to remove unnecessary branches and keep the repository organized"}, {"title": "Automating repository maintenance", "description": "Integrate this script into a CI/CD pipeline to regularly clean up the repository"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:46.468592+00', 10),
	(77, 1316, 'This file guides the process of staging changes in a Git repository, reviewing pending changes with `git status --short`, ensuring no secrets are present in the changes with `git diff --`, and generating a Conventional Commit message with specific formatting rules, such as using feat, fix, or other types and following a particular structure for the commit subject and body.', '[{"title": "Preparing Code for Review", "description": "Use this guide to ensure your code changes are properly formatted and committed before submitting for review"}, {"title": "Maintaining a Clean Git History", "description": "Follow these steps to keep your Git history organized and easy to understand"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:47.748018+00', 15),
	(78, 1317, 'This file outlines a step-by-step process for committing and pushing code changes to a Git repository while adhering to specific governance rules, including running local checks with /review, staging changes, crafting Conventional Commit messages, and triggering remote checks with GitHub Actions.', '[{"title": "Ensuring Code Quality", "description": "Following the outlined steps helps ensure that code changes meet the project''s quality standards before being pushed to the remote repository."}, {"title": "Streamlining Development Workflow", "description": "By automating local checks and triggering remote workflows, developers can focus on writing code while maintaining adherence to project governance rules."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:49.037293+00', 15),
	(79, 1318, 'This file automates the creation of a pull request from the current branch, ensuring that local checks like /review and /security-scan have passed, and the ci-quality-gate workflow has succeeded for the source branch, before creating the PR using GitHub CLI with a conventional title and body, and adding labels.', '[{"title": "Automating Pull Requests", "description": "Use this workflow to automate the creation of pull requests, ensuring that all necessary checks have passed before creating the PR."}, {"title": "Streamlining Code Review", "description": "This workflow helps streamline the code review process by automating the creation of pull requests and ensuring that all necessary checks have been completed."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:50.338825+00', 11),
	(80, 1319, 'This file runs an 8-phase plugin audit pipeline on a skill directory, executing phases sequentially, including discovery, structure validation, quality scoring, script testing, security audit, marketplace and plugin compliance, ecosystem integration, and domain code review, with auto-fixing of non-critical issues and user prompting for critical decisions, utilizing tools such as python3, skill_validator.py, quality_scorer.py, and skill_security_auditor.py.', '[{"title": "Plugin Development", "description": "Use this plugin audit pipeline to ensure plugins are thoroughly tested and validated before deployment."}, {"title": "Skill Validation", "description": "Utilize this pipeline to validate skills and ensure they meet the required standards and criteria."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:36:51.7307+00', 6),
	(81, 1320, 'This file provides a step-by-step guide to running a local review gate before pushing code changes, including installing tooling, linting GitHub workflows, checking Python syntax, performing a Markdown sanity check, and optionally auditing dependencies using safety checks, all of which are designed to ensure code quality and integrity.', '[{"title": "Pre-push Code Review", "description": "Use this guide to ensure code quality and catch potential issues before pushing changes to a repository."}, {"title": "Automated Testing and Linting", "description": "Implement this review gate process to automate testing and linting of code, reducing manual effort and improving overall code health."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:52.865628+00', 15),
	(82, 1321, 'This file outlines a security scanning workflow that checks for committed secrets and audits Python dependencies using tools like gitleaks and safety, ensuring a clean pass before proceeding with the commit and push workflow.', '[{"title": "Pre-Commit Security Check", "description": "Use this guide to ensure your code is secure before committing and pushing it to the repository."}, {"title": "Dependency Management", "description": "Follow these steps to audit your Python dependencies and ensure they are secure and up-to-date."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:36:54.000869+00', 15),
	(83, 1322, 'This file executes a comprehensive SEO audit on documentation files, covering seven phases: discovery, meta tags, content quality, keywords, links, sitemap, and report. It utilizes various scripts, including seo_checker.py, content_scorer.py, and humanizer_scorer.py, to analyze and optimize title tags, descriptions, headings, readability, and link integrity. The audit also detects AI-generated content, identifies broken links, and rebuilds the site''s sitemap. It provides a detailed report on pages scanned, issues found, auto-fixes applied, and manual review items.', '[{"title": "Optimize Documentation for Search Engines", "description": "Use this tool to improve the search engine ranking of documentation pages by optimizing meta tags, content quality, and link integrity."}, {"title": "Identify and Fix AI-Generated Content", "description": "Utilize the humanizer_scorer.py script to detect AI-generated content and fix AI clichés to improve the overall quality of documentation pages."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:36:55.580249+00', 10),
	(84, 1323, 'This file provides a step-by-step guide to update all documentation related files after creating or modifying skills, agents, or commands in a repository. It involves scanning the working tree for changes, running sync scripts for Codex and Gemini CLI, updating plugin.json and marketplace.json files, and regenerating GitHub Pages. The guide also includes verification steps for consistency and accuracy across all updated files.', '[{"title": "Maintaining Repository Documentation", "description": "Use this guide to keep repository documentation up-to-date after creating or modifying skills, agents, or commands."}, {"title": "Ensuring Consistency Across Files", "description": "Follow the steps in this guide to verify consistency and accuracy across all updated files, including plugin.json, marketplace.json, and GitHub Pages."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:37:01.842235+00', 15),
	(85, 1324, 'This file describes a collection of pre-configured agent personas with curated skill loadouts, workflows, and distinct personalities, including personas like Startup CTO, Growth Marketer, and Solo Founder, which can be used with tools like Claude Code and Cursor, and provides a template for creating custom personas with specific characteristics such as identity, mission, rules, capabilities, and workflows.', '[{"title": "Technical Co-Founders", "description": "Using the Startup CTO persona to make technical decisions and build a team"}, {"title": "Content-Led Growth", "description": "Using the Growth Marketer persona to launch and grow a product"}, {"title": "One-Person Startups", "description": "Using the Solo Founder persona to build and manage a side project"}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:37:08.639109+00', 1),
	(86, 1325, 'This agent utilizes tools like Read, Write, Bash, Grep, and Glob to execute its core mission, which includes key responsibilities such as following specific rules and leveraging core capabilities to achieve measurable outcomes. It operates with a defined personality, role, and memory, allowing it to learn and retain expertise over time, including pattern recognition and building on its knowledge base.', '[{"title": "Automated System Administration", "description": "This agent can be used to automate system administration tasks, such as file management, user account management, and system monitoring, by leveraging its capabilities in Bash, Grep, and Glob."}, {"title": "Data Analysis and Processing", "description": "The agent''s skills in data analysis and processing can be applied to various domains, including data science, scientific research, and business intelligence, to extract insights and meaningful patterns from large datasets."}]', 'stable', 8, 'llama-3.3-70b-versatile', '2026-05-11 10:37:15.484387+00', 1),
	(87, 1326, 'The a11y-audit skill provides a comprehensive accessibility audit pipeline for modern web applications, scanning for WCAG 2.2 Level A and AA violations, generating framework-specific fix code, and producing stakeholder-ready compliance reports. It integrates into CI/CD pipelines to prevent accessibility regressions and supports various frameworks such as React, Next.js, Vue, Angular, Svelte, and plain HTML.', '[{"title": "Accessibility Audit for Web Applications", "description": "Use the a11y-audit skill to scan your web application for accessibility violations and generate fix code to ensure compliance with WCAG 2.2 Level A and AA standards."}, {"title": "CI/CD Pipeline Integration", "description": "Integrate the a11y-audit skill into your CI/CD pipeline to automate accessibility testing and prevent regressions."}, {"title": "Manual Testing Checklist", "description": "Use the a11y-audit skill''s testing checklist to manually test your web application for accessibility issues."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:37:31.438179+00', 1),
	(88, 1327, 'This file provides a comprehensive guide to designing and implementing A/B tests, covering key principles such as hypothesis-driven testing, statistical rigor, and the importance of measuring what matters. It outlines a structured approach to test design, including defining test context, understanding current state and constraints, and identifying primary, secondary, and guardrail metrics. The file also discusses best practices for traffic allocation, implementation, and analysis, and highlights common mistakes to avoid in test design, execution, and analysis.', '[{"title": "Improving Conversion Rates", "description": "Use this guide to design and implement A/B tests that help improve conversion rates on a website or landing page."}, {"title": "Optimizing Marketing Campaigns", "description": "Apply the principles outlined in this guide to optimize marketing campaigns and improve their effectiveness."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:37:44.203057+00', 15),
	(89, 1328, 'This file is a comprehensive guide for generating, iterating, and scaling ad creative for paid advertising, covering various platforms such as Google, Meta, LinkedIn, Twitter, and TikTok, and providing workflows, frameworks, and formulas for creating effective ad copy, including benefit-first, curiosity, social proof, and urgency-based approaches, as well as a quality checklist and proactive triggers for ensuring high-quality ad copy', '[{"title": "Generating Ad Copy from Scratch", "description": "Use this skill to generate ad copy for a new product or service, following the provided workflows and frameworks to create effective ad copy for various platforms"}, {"title": "Iterating on Existing Ad Copy", "description": "Use this skill to analyze and improve existing ad copy, applying the provided formulas and quality checklist to increase ad performance and conversion rates"}, {"title": "Scaling Ad Creative for Multiple Platforms", "description": "Use this skill to scale ad creative for multiple platforms, using the provided creative matrix and output artifacts to efficiently generate and validate ad copy for different audiences and platforms"}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:38:02.861471+00', 1),
	(92, 1331, 'This file outlines the inter-agent communication protocol for C-suite agent teams, defining invocation syntax, loop prevention, isolation rules, and response formats to ensure effective and structured communication between agents, preventing chaos and ensuring that each agent can query another using a standardized syntax and receive responses in a consistent format, with features such as invocation, response, broadcast, and peer verification to facilitate cross-functional analysis and decision-making.', '[{"title": "Cross-Functional Analysis", "description": "Agents can use the protocol to query each other and perform cross-functional analysis, ensuring that all relevant perspectives are considered in the decision-making process."}, {"title": "Board Meeting Preparation", "description": "The protocol can be used to prepare for board meetings by facilitating the exchange of information and ideas between agents, resulting in more informed and effective decision-making."}, {"title": "Crisis Management", "description": "In crisis situations, the protocol enables rapid and structured communication between agents, allowing for swift and effective response to critical issues."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:38:57.530676+00', NULL),
	(94, 1333, 'The AgentHub plugin enables multi-agent collaboration by spawning N parallel subagents competing on the same task via git worktree isolation. It supports various commands like /hub:init, /hub:spawn, /hub:status, /hub:eval, and /hub:merge to manage the collaboration session. The plugin also provides templates for different use cases such as optimization, refactoring, and test writing, and allows for evaluation of results by metric or LLM judge.', '[{"title": "Code Optimization", "description": "Use AgentHub to optimize code performance by spawning multiple agents to compete on the same task"}, {"title": "Content Variation", "description": "Use AgentHub to generate content variations by spawning multiple agents to work on the same task"}, {"title": "Research Exploration", "description": "Use AgentHub to explore different research approaches by spawning multiple agents to work on the same task"}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:39:20.435979+00', 6),
	(90, 1329, 'The adversarial-reviewer skill performs a thorough code review by adopting three hostile personas: Saboteur, New Hire, and Security Auditor. Each persona must find at least one issue, eliminating rubber-stamp reviews. The skill promotes findings caught by 2+ personas to the next severity level, providing a structured verdict with clear merge guidance. It can be used to review staged or unstaged changes, specific files, or last commits, and is particularly useful for security-sensitive code or when a second opinion is needed.', '[{"title": "Pre-Merge Code Review", "description": "Use the adversarial-reviewer skill to review code before merging a PR, ensuring that the code meets the required standards and is free from critical issues."}, {"title": "Security-Sensitive Code Review", "description": "Utilize the adversarial-reviewer skill to review security-sensitive code, such as authentication or payment processing, to identify potential vulnerabilities and ensure the code is secure."}, {"title": "Second Opinion on Code Quality", "description": "Run the adversarial-reviewer skill to get a second opinion on code quality, especially when the initial review was easy or when the code feels off, to ensure that the code meets the required standards."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:38:20.342713+00', 1),
	(91, 1330, 'The Agent Designer skill provides a comprehensive framework for designing, architecting, and evaluating multi-agent systems, including agent architecture patterns, tool design principles, communication strategies, and performance evaluation frameworks. It supports various architecture patterns such as single agent, supervisor, swarm, hierarchical, and pipeline patterns, and defines common agent archetypes like coordinator, specialist, interface, and monitor agents. The skill also covers tool design principles, including schema design, error handling, and idempotency requirements, as well as communication patterns like message passing, shared state, and event-driven architecture. Additionally, it emphasizes the importance of guardrails and safety, input validation, output filtering, and human-in-the-loop feedback mechanisms. The skill offers evaluation frameworks for task completion metrics, quality assessment, cost analysis, and latency distribution, and provides guidance on orchestration strategies, memory patterns, scaling considerations, and failure handling mechanisms.', '[{"title": "Designing a Multi-Agent System for Autonomous Vehicles", "description": "Using the Agent Designer skill to architect a system that coordinates multiple agents for tasks like navigation, obstacle detection, and traffic management."}, {"title": "Building a Scalable E-commerce Platform with Multi-Agent Architecture", "description": "Applying the Agent Designer skill to design an e-commerce platform that utilizes multiple agents for tasks like order processing, inventory management, and customer service."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:38:36.661694+00', 1),
	(93, 1332, 'This file provides a comprehensive guide for designing production-grade multi-agent workflows, including workflow pattern selection, skeleton config generation, context and cost discipline, error recovery, and retry strategy scaffolding. It offers various workflow patterns such as sequential, parallel, router, orchestrator, and evaluator, and provides a workflow scaffolder script to generate workflow skeletons. The guide also outlines a recommended workflow, common pitfalls to avoid, and best practices for designing efficient workflows.', '[{"title": "Complex Task Automation", "description": "Use the Agent Workflow Designer to automate complex tasks that require multiple agents and explicit boundaries."}, {"title": "Quality Gate Implementation", "description": "Implement quality gates using the evaluator pattern to ensure high-quality outputs in multi-agent workflows."}, {"title": "Incident Response", "description": "Use the orchestrator pattern to coordinate specialist agents for incident response and triage."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:39:13.758521+00', 15),
	(96, 1335, 'This AI security assessment skill detects prompt injection, jailbreak vulnerabilities, model inversion risk, data poisoning exposure, and agent tool abuse in AI/ML systems, utilizing tools like ai_threat_scanner.py to scan prompts and score risks, with coverage of MITRE ATLAS techniques and support for various access levels and target types.', '[{"title": "AI Model Security Assessment", "description": "Use this skill to assess the security of AI/ML models against various threats, including prompt injection and data poisoning, and to identify vulnerabilities and risks."}, {"title": "AI-Powered Application Security Testing", "description": "Integrate this skill into application security testing workflows to identify and mitigate AI-specific security risks, such as model inversion and agent tool abuse."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:39:59.413499+00', 1),
	(95, 1334, 'The Agile Product Owner skill provides a comprehensive toolkit for backlog management and sprint execution, including user story generation, acceptance criteria patterns, epic breakdown, sprint planning, and velocity tracking. It utilizes INVEST criteria validation, Given-When-Then templates, and story point estimation to ensure high-quality stories. The skill also offers a systematic approach to epic splitting, sprint capacity calculation, and backlog prioritization, making it a valuable asset for product owners and agile teams.', '[{"title": "Backlog Management", "description": "Use the Agile Product Owner skill to manage and prioritize the product backlog, ensuring that the development team has a clear understanding of the requirements and can deliver high-quality features."}, {"title": "Sprint Planning", "description": "Utilize the skill''s sprint planning capabilities to calculate team capacity, select stories, and identify dependencies, resulting in a well-structured sprint plan that sets the team up for success."}, {"title": "Epic Breakdown", "description": "Leverage the skill''s epic breakdown techniques to divide large features into smaller, manageable stories, enabling the team to deliver incremental value and make progress on complex projects."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:39:36.151399+00', 1),
	(97, 1336, 'This skill provides a comprehensive guide to optimizing content for AI search engines, including ChatGPT, Perplexity, Google AI Overviews, Claude, Gemini, and Microsoft Copilot. It offers a structured approach to AI SEO, covering three modes: AI visibility audit, content optimization, and monitoring. The skill includes tools and techniques such as definition blocks, numbered steps, comparison tables, FAQ blocks, and schema markup to improve content extractability and authority.', '[{"title": "Optimizing Content for AI Search Engines", "description": "Use this skill to optimize your content and increase its visibility in AI search engine results, such as ChatGPT, Perplexity, and Google AI Overviews."}, {"title": "Improving Content Extractability and Authority", "description": "Apply the techniques and tools provided in this skill to improve the extractability and authority of your content, making it more citable by AI systems."}]', 'stable', 9, 'llama-3.3-70b-versatile', '2026-05-11 10:40:30.861065+00', 1);
